commands.syntax:
case $VAR in
  pola1) perintah ;;
  pola2) perintah ;;
  *) default ;;
esac

commands.examples:
#!/bin/bash
case $1 in
  start)
    echo "Starting service..."
    ;;
  stop)
    echo "Stopping service..."
    ;;
  restart|reload)
    echo "Restarting service..."
    ;;
  status)
    echo "Service is running"
    ;;
  *)
    echo "Usage: $0 {start|stop|restart|status}"
    exit 1
    ;;
esac

commands.syntax:
function nama() {
  perintah
}
# atau
nama() {
  perintah
}
